    {"question_text": "What is the output?\n\nclass PartitionedQueue:\n    def __init__(self, num_partitions=3):\n        self.partitions = [[] for _ in range(num_partitions)]\n    def produce(self, key, msg):\n        p = hash(key) % len(self.partitions)\n        self.partitions[p].append(msg)\n    def produce_roundrobin(self, messages):\n        for i, msg in enumerate(messages):\n            self.partitions[i % len(self.partitions)].append(msg)\n    def get_sizes(self): return [len(p) for p in self.partitions]\n\npq = PartitionedQueue()\npq.produce_roundrobin([f\"m{i}\" for i in range(9)])\nsizes = pq.get_sizes()\nprint(sum(sizes), len(sizes))", "correct_answer": "A", "difficulty": "advanced", "topic": "system_design", "option_a": "9 3", "option_b": "9 9", "option_c": "3 3", "option_d": "0 3"},
